    """
    Checks if the subtitle is positioned directly below the main title on slide 1 using a vision model.
    """
    slide_num = 1
    main_title = 'Revisiting Classical Social Experiments'
    subtitle = 'A Comprehensive Review'
    try:
        mod_img = [s.image_path for s in modified_ppt_screenshots if s.slide_number == slide_num][0]
        prompt = f"Is the subtitle '{subtitle}' positioned directly below the main title '{main_title}' and horizontally aligned? Reply Yes, Partially, or No."
        result = vlm_call(prompt, [mod_img], temperature=0.0, max_tokens=10)
        if 'yes' in result.lower():
            return ("Subtitle is positioned directly below the main title.", 1.0)
        elif 'partially' in result.lower():
            return ("Subtitle is below the title, but not horizontally aligned.", 0.7)
        else:
            return ("Subtitle is not visually positioned below the main title.", 0.0)
    except IndexError:
        return (f"Slide {slide_num} not found in modified presentation.", 0.0)
    except Exception as e:
        return (f"Unable to verify subtitle position: {e}", 0.0)

def compute_score() -> tuple[str, float]:
    # Check ppt_diff for any changes outside of slide 1
    # Check slides added/removed/modified
    problems = []
    for s in ppt_diff.added_slides:
        if s.slide_number != 1:
            problems.append(f"Added slide {s.slide_number}")
    for s in ppt_diff.removed_slides:
        if s.slide_number != 1:
            problems.append(f"Removed slide {s.slide_number}")
    for s1, s2 in ppt_diff.modified_slides:
        if s1.slide_number != 1:
            problems.append(f"Modified slide {s1.slide_number}")
    # Check animations/transitions on other slides
    for eff in ppt_diff.added_animations + ppt_diff.removed_animations:
        # Need to map slide_id to number; assume slide_id for slide 1 is same in both
        if hasattr(eff, 'slide_id'):
            # Can't directly check number, so count as extraneous
            problems.append(f"Animation change on slide {eff.slide_id}")
    for tr in ppt_diff.added_transitions + ppt_diff.removed_transitions:
        if hasattr(tr, 'slide_id'):
            problems.append(f"Transition change on slide {tr.slide_id}")
    if problems:
        return "Extraneous changes elsewhere: " + ", ".join(problems), 0.0
    return "No extraneous changes elsewhere in the presentation.", 1.0
